const raw = $input.first().json;
const d = raw.body ?? raw;

const emoji = {
  FORMULARIO: '📋',
  CHAT:       '💬',
  WHATSAPP:   '📱',
  REFERIDO:   '🤝',
  OTRO:       '📌',
};
const src = emoji[d.source] ?? '📌';

const hora = d.timestamp
  ? new Date(d.timestamp).toLocaleString('es-EC', { timeZone: 'America/Guayaquil' })
  : new Date().toLocaleString('es-EC', { timeZone: 'America/Guayaquil' });

const lineas = [
  `¡Hola, Dra. Medrano! 👋 Tienes un nuevo lead de paciente.`,
  '',
  '🩺 *Datos del paciente interesado:*',
  '',
  `👤 *Nombre:* ${d.patientName ?? d.name ?? '—'}`,
  d.patientPhone || d.phone ? `📞 *Teléfono:* ${d.patientPhone ?? d.phone}` : null,
  d.patientEmail || d.email ? `📧 *Email:* ${d.patientEmail ?? d.email}` : null,
  d.message ? `💬 *Mensaje:* ${d.message}` : null,
  `${src} *Origen:* ${d.source ?? '—'}`,
  `🕐 *Fecha:* ${hora}`,
  '',
  '💡 _Responde pronto para aumentar la tasa de conversión._',
].filter(l => l !== null);

const message = lineas.join('\n');

// WhatsApp personal de la Dra. Medrano (sin + ni espacios)
const number = '593982678350';

return [{ json: { message, number } }];
